import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import List, Optional, Tuple

import torch
from peft import PeftModel
from transformers import AutoProcessor, Qwen2_5_VLForConditionalGeneration

MIN_PIXELS = 256 * 28 * 28
MAX_PIXELS = 512 * 28 * 28
GRID = 1000.0


@dataclass
class ParsedPrediction:
    kind: str
    values: List[float]
    raw_text: str = ""


def _read_json(path: Path):
    try:
        return json.loads(path.read_text())
    except Exception:
        return {}


def _has_model_files(path: Path) -> bool:
    if not path.exists() or not path.is_dir():
        return False
    needed = [
        "config.json",
        "model.safetensors.index.json",
        "model-00001-of-00002.safetensors",
        "pytorch_model.bin",
    ]
    return any((path / x).exists() for x in needed)


def resolve_base_model_dir(checkpoint: str) -> str:
    ckpt = Path(checkpoint).resolve()
    ckpt_dir = ckpt if ckpt.is_dir() else ckpt.parent
    meta = _read_json(ckpt_dir / "meta.json")
    cwd = Path.cwd().resolve()
    candidates = [
        ckpt_dir / "base_model",
        ckpt_dir.parent / "base_model",
        ckpt_dir.parent / "baseline" / "base_model",
        cwd / "checkpoints" / ckpt_dir.name / "base_model",
        cwd / "checkpoints" / "baseline" / "base_model",
        Path("/workspace/checkpoints") / ckpt_dir.name / "base_model",
        Path("/workspace/checkpoints/baseline/base_model"),
    ]
    for k in ["base_model_dir", "base_model", "base_dir"]:
        v = meta.get(k)
        if v:
            p = Path(v)
            candidates.append(p if p.is_absolute() else (ckpt_dir / p).resolve())
            candidates.append(p if p.is_absolute() else (cwd / p).resolve())
    seen = set()
    for c in candidates:
        s = str(c)
        if s in seen:
            continue
        seen.add(s)
        if _has_model_files(c):
            return s
    raise FileNotFoundError(f"base model not found for checkpoint {checkpoint}")


def load_model_for_inference(checkpoint: str, min_pixels: int = MIN_PIXELS, max_pixels: int = MAX_PIXELS):
    ckpt = Path(checkpoint).resolve()
    base_dir = resolve_base_model_dir(checkpoint)

    proc_candidates = []
    if (ckpt / "processor").exists():
        proc_candidates.append(str(ckpt / "processor"))
    proc_candidates += [str(ckpt), str(base_dir)]
    processor = None
    last_err = None
    for cand in proc_candidates:
        try:
            processor = AutoProcessor.from_pretrained(
                cand,
                local_files_only=True,
                trust_remote_code=False,
                min_pixels=min_pixels,
                max_pixels=max_pixels,
            )
            break
        except Exception as e:
            last_err = e
    if processor is None:
        raise last_err

    model = Qwen2_5_VLForConditionalGeneration.from_pretrained(
        base_dir,
        torch_dtype=torch.bfloat16,
        local_files_only=True,
        trust_remote_code=False,
        device_map="auto",
    )
    if (ckpt / "adapter_config.json").exists():
        model = PeftModel.from_pretrained(model, str(ckpt), local_files_only=True)
    model.eval()
    return model, processor


def build_messages(instruction: str):
    text = (
        "Locate the target UI element described by the instruction. "
        "Return only one point in 0-1000 image coordinates using format <point>x y</point>.\n"
        f"Instruction: {instruction}"
    )
    return [{"role": "user", "content": [{"type": "image"}, {"type": "text", "text": text}]}]


def _extract_numbers(text: str) -> List[float]:
    return [float(x) for x in re.findall(r"-?\d+(?:\.\d+)?", text)]


def parse_prediction_text(raw_text: str) -> Optional[ParsedPrediction]:
    if raw_text is None:
        return None
    text = raw_text.strip()
    if not text:
        return None

    m = re.search(r"<point>\s*([^<]+?)\s*</point>", text, flags=re.I | re.S)
    if m:
        nums = _extract_numbers(m.group(1))
        if len(nums) >= 2:
            return ParsedPrediction("point", nums[:2], text)

    m = re.search(r"<box>\s*([^<]+?)\s*</box>", text, flags=re.I | re.S)
    if m:
        nums = _extract_numbers(m.group(1))
        if len(nums) >= 4:
            x1, y1, x2, y2 = nums[:4]
            return ParsedPrediction("point", [(x1 + x2) / 2.0, (y1 + y2) / 2.0], text)

    m = re.search(r"<bbox>\s*([^<]+?)\s*</bbox>", text, flags=re.I | re.S)
    if m:
        nums = _extract_numbers(m.group(1))
        if len(nums) >= 4:
            x1, y1, x2, y2 = nums[:4]
            return ParsedPrediction("point", [(x1 + x2) / 2.0, (y1 + y2) / 2.0], text)

    nums = _extract_numbers(text)
    if len(nums) >= 4:
        x1, y1, x2, y2 = nums[:4]
        return ParsedPrediction("point", [(x1 + x2) / 2.0, (y1 + y2) / 2.0], text)
    if len(nums) >= 2:
        return ParsedPrediction("point", nums[:2], text)
    return None


def _clip(x: float, lo: float, hi: float) -> float:
    return float(max(lo, min(hi, x)))


def _grid_to_abs(x: float, y: float, width: float, height: float) -> Tuple[float, float]:
    if 0.0 <= x <= GRID and 0.0 <= y <= GRID:
        ax = x / GRID * width
        ay = y / GRID * height
    else:
        ax, ay = x, y
    return _clip(ax, 0.0, width), _clip(ay, 0.0, height)


@torch.inference_mode()
def generate_raw(model, processor, image, instruction: str, max_new_tokens: int = 16) -> str:
    messages = build_messages(instruction)
    text = processor.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
    inputs = processor(text=[text], images=[image], padding=True, return_tensors="pt")
    device = next(model.parameters()).device
    moved = {}
    for k, v in inputs.items():
        if hasattr(v, "to"):
            moved[k] = v.to(device)
        else:
            moved[k] = v
    out = model.generate(**moved, max_new_tokens=max_new_tokens, do_sample=False)
    prompt_len = moved["input_ids"].shape[1]
    gen_ids = out[:, prompt_len:]
    decoded = processor.batch_decode(gen_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)
    return decoded[0].strip() if decoded else ""


@torch.inference_mode()
def generate_prediction(model, processor, image, instruction: str, image_width: float, image_height: float):
    try:
        raw = generate_raw(model, processor, image, instruction)
        parsed = parse_prediction_text(raw)
        if parsed is not None and len(parsed.values) >= 2:
            x, y = _grid_to_abs(parsed.values[0], parsed.values[1], float(image_width), float(image_height))
            return {"point": [x, y], "raw": raw}
    except Exception:
        pass
    return {"point": [float(image_width) / 2.0, float(image_height) / 2.0], "raw": ""}
